(window.webpackJsonp=window.webpackJsonp||[]).push([[165],{460:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">stones</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">K</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> mergeStones = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">stones, K</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> N=stones.length\\n  <span class=\\"hljs-keyword\\">if</span>((N<span class=\\"hljs-number\\">-1</span>) % (K<span class=\\"hljs-number\\">-1</span>)!==<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">let</span> dp=<span class=\\"hljs-built_in\\">Array</span>(N).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-number\\">0</span>))\\n  <span class=\\"hljs-keyword\\">let</span> prefix=<span class=\\"hljs-built_in\\">Array</span>(N+<span class=\\"hljs-number\\">1</span>).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;N;i++){\\n    prefix[i+<span class=\\"hljs-number\\">1</span>]=prefix[i]+stones[i]\\n  }\\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=K<span class=\\"hljs-number\\">-1</span>;i&lt;N;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;N-i;j++){\\n      <span class=\\"hljs-keyword\\">let</span> k=i+j\\n      dp[j][k]=<span class=\\"hljs-literal\\">Infinity</span>\\n      <span class=\\"hljs-comment\\">// console.log(j,k,\'----\')</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> l=j;l&lt;k;l+=K<span class=\\"hljs-number\\">-1</span>){\\n        dp[j][k] = <span class=\\"hljs-built_in\\">Math</span>.min(dp[j][k], dp[j][l] + dp[l + <span class=\\"hljs-number\\">1</span>][k]);\\n        <span class=\\"hljs-comment\\">// console.log(dp[j][k])</span>\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>((k-j) % (K<span class=\\"hljs-number\\">-1</span>)===<span class=\\"hljs-number\\">0</span>){\\n        dp[j][k]+=prefix[k+<span class=\\"hljs-number\\">1</span>]-prefix[j]\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(dp)</span>\\n  <span class=\\"hljs-keyword\\">return</span> dp[<span class=\\"hljs-number\\">0</span>][N<span class=\\"hljs-number\\">-1</span>]\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">mergeStones</span><span class=\\"hljs-params\\">(self, stones, K)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type stones: List[int]\\n        :type K: int\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        N=len(stones)\\n        sums=[<span class=\\"hljs-number\\">0</span>]*(N+<span class=\\"hljs-number\\">1</span>)\\n        memo={}\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(N):\\n          sums[i+<span class=\\"hljs-number\\">1</span>]=sums[i]+stones[i]\\n        <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">dp</span><span class=\\"hljs-params\\">(i,j,m)</span>:</span>\\n          <span class=\\"hljs-keyword\\">if</span> i==j:\\n            <span class=\\"hljs-keyword\\">if</span> m==<span class=\\"hljs-number\\">1</span>:<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n            <span class=\\"hljs-keyword\\">return</span> float(<span class=\\"hljs-string\\">\'inf\'</span>)\\n          <span class=\\"hljs-keyword\\">if</span> m==<span class=\\"hljs-number\\">1</span>:\\n            <span class=\\"hljs-keyword\\">return</span> dp(i,j,K)+sums[j+<span class=\\"hljs-number\\">1</span>]-sums[i]\\n          <span class=\\"hljs-keyword\\">if</span> (i, j, m) <span class=\\"hljs-keyword\\">in</span> memo:\\n            <span class=\\"hljs-keyword\\">return</span> memo[i, j, m]\\n          res=float(<span class=\\"hljs-string\\">\'inf\'</span>)\\n          <span class=\\"hljs-keyword\\">for</span> mid <span class=\\"hljs-keyword\\">in</span> range(i,j,K<span class=\\"hljs-number\\">-1</span>):\\n            res=min(res,dp(i,mid,<span class=\\"hljs-number\\">1</span>)+dp(mid+<span class=\\"hljs-number\\">1</span>,j,m<span class=\\"hljs-number\\">-1</span>))\\n          memo[i, j, m] = res\\n          <span class=\\"hljs-keyword\\">return</span> res\\n        res=dp(<span class=\\"hljs-number\\">0</span>,N<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">1</span>)\\n        <span class=\\"hljs-keyword\\">if</span> res==float(<span class=\\"hljs-string\\">\'inf\'</span>):<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">return</span> res\\n</code></pre>\\n"],"titleSlug":"minimum-cost-to-merge-stones","hasThinking":false,"content":"<p>\u6709 <code>N</code> \u5806\u77f3\u5934\u6392\u6210\u4e00\u6392\uff0c\u7b2c <code>i</code> \u5806\u4e2d\u6709&nbsp;<code>stones[i]</code>&nbsp;\u5757\u77f3\u5934\u3002</p>\\n\\n<p>\u6bcf\u6b21<em>\u79fb\u52a8\uff08move\uff09</em>\u9700\u8981\u5c06<strong>\u8fde\u7eed\u7684</strong>&nbsp;<code>K</code>&nbsp;\u5806\u77f3\u5934\u5408\u5e76\u4e3a\u4e00\u5806\uff0c\u800c\u8fd9\u4e2a\u79fb\u52a8\u7684\u6210\u672c\u4e3a\u8fd9&nbsp;<code>K</code>&nbsp;\u5806\u77f3\u5934\u7684\u603b\u6570\u3002</p>\\n\\n<p>\u627e\u51fa\u628a\u6240\u6709\u77f3\u5934\u5408\u5e76\u6210\u4e00\u5806\u7684\u6700\u4f4e\u6210\u672c\u3002\u5982\u679c\u4e0d\u53ef\u80fd\uff0c\u8fd4\u56de <code>-1</code> \u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>stones = [3,2,4,1], K = 2\\n<strong>\u8f93\u51fa\uff1a</strong>20\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u4ece [3, 2, 4, 1] \u5f00\u59cb\u3002\\n\u5408\u5e76 [3, 2]\uff0c\u6210\u672c\u4e3a 5\uff0c\u5269\u4e0b [5, 4, 1]\u3002\\n\u5408\u5e76 [4, 1]\uff0c\u6210\u672c\u4e3a 5\uff0c\u5269\u4e0b [5, 5]\u3002\\n\u5408\u5e76 [5, 5]\uff0c\u6210\u672c\u4e3a 10\uff0c\u5269\u4e0b [10]\u3002\\n\u603b\u6210\u672c 20\uff0c\u8fd9\u662f\u53ef\u80fd\u7684\u6700\u5c0f\u503c\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>stones = [3,2,4,1], K = 3\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n<strong>\u89e3\u91ca\uff1a</strong>\u4efb\u4f55\u5408\u5e76\u64cd\u4f5c\u540e\uff0c\u90fd\u4f1a\u5269\u4e0b 2 \u5806\uff0c\u6211\u4eec\u65e0\u6cd5\u518d\u8fdb\u884c\u5408\u5e76\u3002\u6240\u4ee5\u8fd9\u9879\u4efb\u52a1\u662f\u4e0d\u53ef\u80fd\u5b8c\u6210\u7684\u3002.\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>stones = [3,5,1,2,6], K = 3\\n<strong>\u8f93\u51fa\uff1a</strong>25\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u4ece [3, 5, 1, 2, 6] \u5f00\u59cb\u3002\\n\u5408\u5e76 [5, 1, 2]\uff0c\u6210\u672c\u4e3a 8\uff0c\u5269\u4e0b [3, 8, 6]\u3002\\n\u5408\u5e76 [3, 8, 6]\uff0c\u6210\u672c\u4e3a 17\uff0c\u5269\u4e0b [17]\u3002\\n\u603b\u6210\u672c 25\uff0c\u8fd9\u662f\u53ef\u80fd\u7684\u6700\u5c0f\u503c\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= stones.length &lt;= 30</code></li>\\n\\t<li><code>2 &lt;= K &lt;= 30</code></li>\\n\\t<li><code>1 &lt;= stones[i] &lt;= 100</code></li>\\n</ul>\\n","title":"1000. \u5408\u5e76\u77f3\u5934\u7684\u6700\u4f4e\u6210\u672c","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["javascript","python"],"uniqueID":"1000"}')}}]);